// Read progress.json and find the next company that hasn't been completed
const fs = require('fs');
const path = require('path');

const BASE = 'C:/Users/USER/Documents/Internship agent';
const PROGRESS = path.join(BASE, 'progress.json');
const COMPANIES = path.join(BASE, 'knowledge/target_companies.json');

let progress = { completed: [], researched: [], current: null };
try { progress = JSON.parse(fs.readFileSync(PROGRESS, 'utf-8')); } catch(e) {}

let companies = [];
try { companies = JSON.parse(fs.readFileSync(COMPANIES, 'utf-8')).companies || []; } catch(e) {}

const next = companies.find(c => !progress.completed.includes(c.name));

if (!next) {
  return [{ json: { done: true, message: `All ${companies.length} companies completed! 🎉`, total: companies.length, completed: progress.completed.length } }];
}

const slug = next.name.toLowerCase().replace(/ /g, '_');
const doneCount = progress.completed.length;

return [{ json: {
  done: false,
  company: next.name,
  domain: next.domain,
  slug,
  progress: `${doneCount}/${companies.length}`,
  doneCount,
  total: companies.length
} }];

const { exec } = require('child_process');
