const cmd = `set PYTHONIOENCODING=utf-8 && cd "${BASE}" && ${py} pipeline.py research --company "${company}"`;
return new Promise((resolve) => {
  exec(cmd, { encoding: 'utf-8', timeout: 300000, maxBuffer: 10 * 1024 * 1024 }, (error, stdout, stderr) => {
