// Check drafts folder and pick only ONE safe company per schedule cycle
const fs = require('fs');
const path = require('path');

const BASE = 'C:/Users/USER/Documents/Internship agent';
const DRAFTS = path.join(BASE, 'drafts');
const PROGRESS = path.join(BASE, 'progress.json');
const SEND_LOG = path.join(BASE, 'send_log.json');
const MAX_PER_DAY = 18;

let progress = { completed: [], researched: [], current: null };
try { progress = JSON.parse(fs.readFileSync(PROGRESS, 'utf-8')); } catch(e) {}

let sendLog = { today: '', sent_today: 0, all_recipients: [] };
try { sendLog = JSON.parse(fs.readFileSync(SEND_LOG, 'utf-8')); } catch(e) {}

const today = new Date().toISOString().split('T')[0];
if (sendLog.today !== today) {
  sendLog.today = today;
  sendLog.sent_today = 0;
  try { fs.writeFileSync(SEND_LOG, JSON.stringify(sendLog, null, 2)); } catch(e) {}
}

const remainingBudget = MAX_PER_DAY - (sendLog.sent_today || 0);
if (remainingBudget <= 0) {
  return [{ json: { hasReady: false, message: `Daily limit reached (${sendLog.sent_today}/${MAX_PER_DAY}). Waiting until tomorrow.` } }];
}

const knownRecipients = new Set((sendLog.all_recipients || []).map(e => String(e).toLowerCase()));

for (const company of (progress.researched || [])) {
  const slug = company.toLowerCase().replace(/ /g, '_');
  const draftsPath = path.join(DRAFTS, `${slug}_drafts.txt`);

  let content = '';
  try {
    content = fs.readFileSync(draftsPath, 'utf-8');
  } catch(e) {
    continue;
  }

  if (!content.includes('---EMAIL---')) continue;

  const blocks = content.split(/---\s*EMAIL\s*---/i).filter(b => b.trim());
  let hasAddress = false;
  let hasUnsents = false;

  for (const block of blocks) {
    const cleaned = block.replace(/---\s*END\s*---.*/is, '').trim();
    if (!cleaned) continue;
    const toMatch = cleaned.match(/^TO:\s*(.+)$/im);
    if (!toMatch) continue;

    const email = toMatch[1].trim().toLowerCase();
    if (!email || !email.includes('@')) continue;

    hasAddress = true;
    if (!knownRecipients.has(email)) {
      hasUnsents = true;
      break;
    }
  }

  if (hasUnsents) {
    return [{ json: { company, slug, draftsContent: content, remainingBudget, hasReady: true } }];
  }

  if (hasAddress) {
    const sentPath = path.join(DRAFTS, `${slug}_drafts_sent.txt`);
    try { fs.renameSync(draftsPath, sentPath); } catch(e) {}

    if (!progress.completed.includes(company)) {
      progress.completed.push(company);
    }
    progress.researched = (progress.researched || []).filter(c => c !== company);
    if (progress.current === company) progress.current = null;

    try { fs.writeFileSync(PROGRESS, JSON.stringify(progress, null, 2)); } catch(e) {}
  }
}

return [{ json: { hasReady: false, message: 'No new unsent drafts ready yet. Waiting for Gemini replies...' } }];

// Parse EMAIL blocks, enforce budget, and pre-filter duplicate recipients
const fs = require('fs');
const path = require('path');

const content = $json.draftsContent || '';
const company = $json.company;
const slug = $json.slug;

const BASE = 'C:/Users/USER/Documents/Internship agent';
const SEND_LOG = path.join(BASE, 'send_log.json');
const MAX_PER_DAY = 18;

let sendLog = { today: '', sent_today: 0, all_recipients: [] };
try { sendLog = JSON.parse(fs.readFileSync(SEND_LOG, 'utf-8')); } catch(e) {}

const today = new Date().toISOString().split('T')[0];
if (sendLog.today !== today) {
  sendLog.today = today;
  sendLog.sent_today = 0;
}

let remainingBudget = Number($json.remainingBudget ?? (MAX_PER_DAY - (sendLog.sent_today || 0)));
if (!Number.isFinite(remainingBudget)) remainingBudget = 0;
if (remainingBudget <= 0) {
  return [{ json: { skip: true, company, message: 'Daily send budget exhausted for today.' } }];
}

const knownRecipients = new Set((sendLog.all_recipients || []).map(e => String(e).toLowerCase()));
const batchRecipients = new Set();
const blocks = content.split(/---\s*EMAIL\s*---/i).filter(b => b.trim());
const emails = [];

for (const block of blocks) {
  if (emails.length >= remainingBudget) break;

  const cleaned = block.replace(/---\s*END\s*---.*/is, '').trim();
  if (!cleaned) continue;

  const toMatch = cleaned.match(/^TO:\s*(.+)$/im);
  const nameMatch = cleaned.match(/^NAME:\s*(.+)$/im);
  const subjectMatch = cleaned.match(/^SUBJECT:\s*(.+)$/im);
  const bodyMatch = cleaned.match(/^BODY:\s*\n([\s\S]*)/im);

  if (!toMatch || !subjectMatch || !bodyMatch) continue;

  const toEmail = toMatch[1].trim();
  const toEmailLower = toEmail.toLowerCase();
  if (!toEmail.includes('@')) continue;
  if (knownRecipients.has(toEmailLower)) continue;
  if (batchRecipients.has(toEmailLower)) continue;

  batchRecipients.add(toEmailLower);
  emails.push({
    company, slug,
    to_email: toEmail,
    to_name: nameMatch ? nameMatch[1].trim() : '',
    subject: subjectMatch[1].trim(),
    body: bodyMatch[1].trim(),
    skip: false
  });
}

if (emails.length === 0) {
  return [{ json: { skip: true, company, message: 'No new unsent EMAIL blocks after duplicate/budget filtering.' } }];
}

return emails.map(e => ({ json: e }));

// After EACH successful send, update send_log + progress safely
const fs = require('fs');
const path = require('path');

const BASE = 'C:/Users/USER/Documents/Internship agent';
const DRAFTS = path.join(BASE, 'drafts');
const PROGRESS = path.join(BASE, 'progress.json');
const SEND_LOG = path.join(BASE, 'send_log.json');

const item = $input.first().json || {};
const company = item.company || '';
const toEmail = String(item.to_email || '').toLowerCase();

if (!company || !toEmail.includes('@')) {
  return [{ json: { status: 'skipped', message: 'No valid sent-email context.' } }];
}

let sendLog = { today: '', sent_today: 0, all_recipients: [] };
try { sendLog = JSON.parse(fs.readFileSync(SEND_LOG, 'utf-8')); } catch(e) {}
const today = new Date().toISOString().split('T')[0];
if (sendLog.today !== today) {
  sendLog.today = today;
  sendLog.sent_today = 0;
}
sendLog.sent_today += 1;
if (!sendLog.all_recipients.includes(toEmail)) {
  sendLog.all_recipients.push(toEmail);
}
fs.writeFileSync(SEND_LOG, JSON.stringify(sendLog, null, 2));

let progress = { completed: [], researched: [], current: null };
try { progress = JSON.parse(fs.readFileSync(PROGRESS, 'utf-8')); } catch(e) {}
if (!progress.completed.includes(company)) {
  progress.completed.push(company);
}
progress.researched = (progress.researched || []).filter(c => c !== company);
if (progress.current === company) progress.current = null;
fs.writeFileSync(PROGRESS, JSON.stringify(progress, null, 2));

const slug = company.toLowerCase().replace(/ /g, '_');
const src = path.join(DRAFTS, `${slug}_drafts.txt`);
const dst = path.join(DRAFTS, `${slug}_drafts_sent.txt`);
try { fs.renameSync(src, dst); } catch(e) {}

const COMPANIES_FILE = path.join(BASE, 'knowledge/target_companies.json');
let total = 0;
try { total = JSON.parse(fs.readFileSync(COMPANIES_FILE, 'utf-8')).companies.length; } catch(e) {}

return [{ json: {
  status: 'sent',
  companies_done: [company],
  emails_sent: 1,
  total_completed: progress.completed.length,
  total_companies: total,
  remaining: total - progress.completed.length,
  daily_sent: sendLog.sent_today,
  message: `Sent 1 email to ${toEmail} for ${company}. ${progress.completed.length}/${total} done. (${sendLog.sent_today}/18 daily limit)`
} }];

// Log skipped emails
const item = $input.first().json;
return [{ json: { status: 'skipped', name: item.to_name, company: item.company, reason: 'no valid email' } }];
